export async function GET(req: Request) {
  const url = new URL(req.url);
  if (url.searchParams.get("key") !== "import2026") {
    return Response.json({ error: "Unauthorized" }, { status: 401 });
  }

  const log: string[] = [];

  // 1. Create missing exercises
  const allExercises = await prisma.exercise.findMany({ select: { id: true, name: true } });
  const exByName = new Map(allExercises.map((e) => [e.name, e.id]));

  for (const ex of NEW_EXERCISES) {
    if (exByName.has(ex.name)) continue;
    const created = await prisma.exercise.create({
      data: { ...ex, isGlobal: true },
    });
    exByName.set(ex.name, created.id);
    log.push(`Created exercise: ${ex.name}`);
  }

  // 2. Create templates
  for (const tpl of TEMPLATES) {
    const existing = await prisma.workoutTemplate.findFirst({ where: { name: tpl.name } });
    if (existing) { log.push(`Template exists: ${tpl.name}`); continue; }
    const created = await prisma.workoutTemplate.create({
      data: { name: tpl.name, templateType: tpl.templateType as any },
    });
    let sortOrder = 1;
    for (const ex of tpl.exercises) {
      const exId = exByName.get(ex.name);
      if (!exId) { log.push(`  WARNING: unknown exercise ${ex.name}`); continue; }
      await prisma.templateExercise.create({
        data: { templateId: created.id, exerciseId: exId, sortOrder: sortOrder++, targetSets: ex.sets, repRangeMin: ex.min, repRangeMax: ex.max },
      });
    }
    log.push(`Created template: ${tpl.name}`);
  }

  // 3. Import sessions
  let imported = 0;
  let skipped = 0;

  for (const sess of SESSIONS) {
    const sessDate = new Date(sess.date);
    const dayStart = new Date(sessDate); dayStart.setHours(0,0,0,0);
    const dayEnd = new Date(sessDate); dayEnd.setHours(23,59,59,999);
    const existing = await prisma.workoutSession.findFirst({
      where: { startedAt: { gte: dayStart, lte: dayEnd } },
    });
    if (existing) { skipped++; continue; }

    const session = await prisma.workoutSession.create({
      data: { startedAt: sessDate, finishedAt: new Date(sessDate.getTime() + 90*60*1000) },
    });

    let sortOrder = 1;
    for (const ex of sess.exercises) {
      const exId = exByName.get(ex.name);
      if (!exId) { log.push(`  WARNING: unknown exercise "${ex.name}"`); continue; }
      if (ex.sets.length === 0) continue;

      const repsArr = ex.sets.map((s: any) => s.reps).filter((r: number) => r > 0);
      const se = await prisma.sessionExercise.create({
        data: {
          sessionId: session.id, exerciseId: exId, sortOrder: sortOrder++,
          exerciseName: ex.name,
          targetSets: ex.sets.length,
          repRangeMin: repsArr.length ? Math.min(...repsArr) : 8,
          repRangeMax: repsArr.length ? Math.max(...repsArr) : 12,
        },
      });

      let setNumber = 1;
      for (const s of ex.sets) {
        await prisma.set.create({
          data: { sessionExerciseId: se.id, setNumber: setNumber++, reps: s.reps || 1, weightKg: s.weightKg, rpe: 7 },
        });
      }
    }
    imported++;
  }
  log.push(`Imported ${imported} sessions, skipped ${skipped}`);

  return Response.json({ ok: true, log });
}
